using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // BREAKING CHANGE 1 — Discriminator property renamed.
            // EF9 changed the discriminator JSON property from "Discriminator" to "$type".
            // Pin it to the EF8 name so existing 500K documents stay readable and
            // direct SQL queries referencing c.Discriminator keep working.
            entity.HasDiscriminator<string>("Discriminator");

            // BREAKING CHANGE 2 — Id format changed.
            // EF8 generated the Cosmos "id" as "Product|123"; EF9 uses just "123".
            // Map a shadow property to the JSON "id" field with the legacy format
            // so lookups against existing documents succeed.
            entity.Property<string>("__id")
                  .ToJsonProperty("id")
                  .HasValueGeneratorFactory<LegacyIdGeneratorFactory>();
            entity.HasKey("__id");

            // BREAKING CHANGE 3 — HasIndex throws at model build time.
            // Cosmos doesn't support traditional indexes; EF8 silently ignored this
            // but EF9 throws. The HasIndex call has been removed.
        });
    }
}

